import React, { useState, useEffect } from 'react';
import { db } from '../firebase';
import { collection, getDocs } from 'firebase/firestore';
import { X, LogOut, FolderOpen, Clock, CheckCircle, AlertCircle, LayoutGrid } from 'lucide-react';

function UserProfile({ user, onClose, onLogout }) {
  const [myProjects, setMyProjects] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchMyProjects = async () => {
      try {
        // Fetch all projects
        const projectsRef = collection(db, "projects");
        const querySnapshot = await getDocs(projectsRef);
        
        // Filter based on BOTH your old database format and the new one
        const projectsList = querySnapshot.docs
          .map(doc => ({ id: doc.id, ...doc.data() }))
          .filter(project => {
            // Your old format (e.g., "Rahul Kumar (23bsccs01)")
            const legacyAuthor = (project.author || "").toLowerCase();
            // Our new format
            const newAuthorName = (project.authorName || "").toLowerCase();
            const newAuthorUsername = (project.authorUsername || "").toLowerCase();

            const currentUserName = (user?.name || "").toLowerCase();
            const currentUserRoll = (user?.username || "").toLowerCase();

            // 1. Check if the old "author" field includes the name or roll number
            if (legacyAuthor.includes(currentUserName) || legacyAuthor.includes(currentUserRoll)) return true;
            
            // 2. Check if the new fields match
            if (newAuthorName === currentUserName || newAuthorUsername === currentUserRoll) return true;

            return false;
          });
        
        setMyProjects(projectsList);
      } catch (error) {
        console.error("Error fetching user projects:", error);
      } finally {
        setLoading(false);
      }
    };

    if (user) {
      fetchMyProjects();
    }
  }, [user]);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6 font-sans">
      {/* Dark Blur Backdrop */}
      <div 
        className="absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity" 
        onClick={onClose}
      ></div>

      {/* Profile Modal */}
      <div className="relative w-full max-w-md bg-[#0a0a0a] border border-white/10 rounded-[2rem] shadow-[0_0_50px_rgba(0,0,0,0.5)] overflow-hidden flex flex-col max-h-[90vh] animate-fade-in-up">
        
        {/* Header Section */}
        <div className="bg-white/5 border-b border-white/10 p-6 relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/20 blur-[50px] rounded-full pointer-events-none"></div>
          
          <button onClick={onClose} className="absolute top-4 right-4 p-2 text-gray-400 hover:text-white hover:bg-white/10 rounded-full transition-all">
            <X className="w-5 h-5" />
          </button>

          <div className="flex items-center gap-4 relative z-10">
            <div className="w-16 h-16 rounded-full bg-gradient-to-tr from-indigo-500 to-purple-500 flex items-center justify-center text-2xl font-bold text-white shadow-lg border-2 border-white/10">
              {user?.name?.charAt(0)?.toUpperCase() || "U"}
            </div>
            <div>
              <h2 className="text-xl font-extrabold text-white tracking-tight">{user?.name || "Student User"}</h2>
              <div className="flex items-center gap-2 mt-1">
                <span className="bg-white/10 text-gray-300 text-[10px] px-2.5 py-1 rounded-full font-semibold uppercase tracking-wider border border-white/5">
                  {user?.role || "Student"}
                </span>
                <span className="text-xs text-gray-500 font-mono">{user?.username}</span>
              </div>
            </div>
          </div>
        </div>

        {/* Content Section */}
        <div className="p-6 flex-1 overflow-y-auto scrollbar-hide">
          <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-4 flex items-center gap-2">
            <FolderOpen className="w-4 h-4" /> My Submissions ({myProjects.length})
          </h3>

          {loading ? (
            <div className="flex flex-col gap-3">
              {[1, 2].map(n => (
                <div key={n} className="h-20 bg-white/5 rounded-2xl animate-pulse border border-white/5"></div>
              ))}
            </div>
          ) : myProjects.length > 0 ? (
            <div className="flex flex-col gap-3">
              {myProjects.map((project) => (
                <div key={project.id} className="bg-white/5 border border-white/10 p-4 rounded-2xl hover:bg-white/10 transition-colors flex justify-between items-center group">
                  <div className="overflow-hidden pr-4">
                    <h4 className="font-bold text-white truncate group-hover:text-indigo-400 transition-colors">{project.title}</h4>
                    <p className="text-xs text-gray-500 mt-1 truncate">{project.category || "Project"}</p>
                  </div>
                  
                  {/* Status Badges */}
                  <div className="shrink-0">
                    {project.status === 'Approved' && (
                      <span className="flex items-center gap-1.5 bg-green-500/10 border border-green-500/20 text-green-400 text-xs px-3 py-1.5 rounded-xl font-semibold">
                        <CheckCircle className="w-3.5 h-3.5" /> Approved
                      </span>
                    )}
                    {project.status === 'Pending' && (
                      <span className="flex items-center gap-1.5 bg-yellow-500/10 border border-yellow-500/20 text-yellow-400 text-xs px-3 py-1.5 rounded-xl font-semibold">
                        <Clock className="w-3.5 h-3.5" /> Pending
                      </span>
                    )}
                    {project.status === 'Rejected' && (
                      <span className="flex items-center gap-1.5 bg-red-500/10 border border-red-500/20 text-red-400 text-xs px-3 py-1.5 rounded-xl font-semibold">
                        <AlertCircle className="w-3.5 h-3.5" /> Rejected
                      </span>
                    )}
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-10 bg-white/5 rounded-2xl border border-white/5">
              <LayoutGrid className="w-10 h-10 text-gray-600 mx-auto mb-3" />
              <p className="text-gray-400 text-sm">No projects submitted yet.</p>
            </div>
          )}
        </div>

        {/* Footer / Logout Section */}
        <div className="p-6 border-t border-white/10 bg-black/20">
          <button 
            onClick={onLogout} 
            className="w-full py-3.5 rounded-xl font-bold text-sm flex justify-center items-center gap-2 bg-red-500/10 text-red-400 hover:bg-red-500/20 hover:text-red-300 border border-red-500/20 transition-all"
          >
            <LogOut className="w-4 h-4" /> Secure Logout
          </button>
        </div>

      </div>
    </div>
  );
}

export default UserProfile;
